import express from "express";
import path from "path";
import fs from "fs";
import { createServer as createViteServer } from "vite";
import dotenv from "dotenv";

dotenv.config();

const app = express();
const PORT = 3000;

// Set payload limit high to support image and video uploads in base64 format
app.use(express.json({ limit: "100mb" }));
app.use(express.urlencoded({ limit: "100mb", extended: true }));

// Paths for data storage
const DATA_DIR = path.join(process.cwd(), "data");
const PORTFOLIO_PATH = path.join(DATA_DIR, "portfolio.json");
const MESSAGES_PATH = path.join(DATA_DIR, "messages.json");
const UPLOADS_DIR = path.join(process.cwd(), "public", "uploads");

// Ensure directories exist
if (!fs.existsSync(DATA_DIR)) {
  fs.mkdirSync(DATA_DIR, { recursive: true });
}
if (!fs.existsSync(UPLOADS_DIR)) {
  fs.mkdirSync(UPLOADS_DIR, { recursive: true });
}

// Serve uploaded files statically at /uploads
app.use("/uploads", express.static(UPLOADS_DIR));

// Helper: Get admin password from env or default
const getAdminPassword = (): string => {
  return process.env.ADMIN_PASSWORD || "admin123";
};

// Middleware: Authenticate admin request
const authenticateAdmin = (req: express.Request, res: express.Response, next: express.NextFunction) => {
  const authHeader = req.headers.authorization;
  if (!authHeader) {
    res.status(401).json({ error: "Ruxsat etilmadi: Token topilmadi." });
    return;
  }
  
  const token = authHeader.replace("Bearer ", "");
  if (token === getAdminPassword()) {
    next();
  } else {
    res.status(403).json({ error: "Ruxsat etilmadi: Noto'g'ri parol." });
  }
};

// --- API ROUTES ---

// 1. Get Portfolio Data
app.get("/api/portfolio", (req, res) => {
  try {
    if (fs.existsSync(PORTFOLIO_PATH)) {
      const data = fs.readFileSync(PORTFOLIO_PATH, "utf-8");
      res.json(JSON.parse(data));
    } else {
      res.status(404).json({ error: "Portfolio ma'lumotlari topilmadi." });
    }
  } catch (error) {
    console.error("GET /api/portfolio xatolik:", error);
    res.status(500).json({ error: "Server ichki xatoligi" });
  }
});

// 2. Update Portfolio Data (Admin only)
app.post("/api/portfolio", authenticateAdmin, (req, res) => {
  try {
    const data = req.body;
    fs.writeFileSync(PORTFOLIO_PATH, JSON.stringify(data, null, 2), "utf-8");
    res.json({ success: true, message: "Portfolio muvaffaqiyatli yangilandi!" });
  } catch (error) {
    console.error("POST /api/portfolio xatolik:", error);
    res.status(500).json({ error: "Server ichki xatoligi" });
  }
});

// 3. Login Endpoint
app.post("/api/login", (req, res) => {
  try {
    const { password } = req.body;
    if (password === getAdminPassword()) {
      res.json({ success: true, token: password });
    } else {
      res.status(401).json({ success: false, error: "Noto'g'ri parol!" });
    }
  } catch (error) {
    console.error("POST /api/login xatolik:", error);
    res.status(500).json({ error: "Server ichki xatoligi" });
  }
});

// 4. Submit Contact Message (Public)
app.post("/api/messages", (req, res) => {
  try {
    const { name, email, phone, message } = req.body;
    if (!name || !message) {
      res.status(400).json({ error: "Ism va xabar maydonlari to'ldirilishi shart." });
      return;
    }

    let messages = [];
    if (fs.existsSync(MESSAGES_PATH)) {
      messages = JSON.parse(fs.readFileSync(MESSAGES_PATH, "utf-8"));
    }

    const newMessage = {
      id: "msg_" + Date.now() + "_" + Math.random().toString(36).substr(2, 9),
      name,
      email: email || "",
      phone: phone || "",
      message,
      date: new Date().toISOString(),
      read: false
    };

    messages.unshift(newMessage); // Prepend new messages to see latest first
    fs.writeFileSync(MESSAGES_PATH, JSON.stringify(messages, null, 2), "utf-8");

    res.json({ success: true, message: "Xabaringiz muvaffaqiyatli yuborildi!" });
  } catch (error) {
    console.error("POST /api/messages xatolik:", error);
    res.status(500).json({ error: "Xabar yuborishda xatolik yuz berdi." });
  }
});

// 5. Get Contact Messages (Admin only)
app.get("/api/messages", authenticateAdmin, (req, res) => {
  try {
    if (fs.existsSync(MESSAGES_PATH)) {
      const messages = JSON.parse(fs.readFileSync(MESSAGES_PATH, "utf-8"));
      res.json(messages);
    } else {
      res.json([]);
    }
  } catch (error) {
    console.error("GET /api/messages xatolik:", error);
    res.status(500).json({ error: "Xabarlarni yuklashda xatolik." });
  }
});

// 6. Mark Message as Read (Admin only)
app.post("/api/messages/:id/read", authenticateAdmin, (req, res) => {
  try {
    const { id } = req.params;
    if (!fs.existsSync(MESSAGES_PATH)) {
      res.status(404).json({ error: "Xabarlar topilmadi." });
      return;
    }

    let messages = JSON.parse(fs.readFileSync(MESSAGES_PATH, "utf-8"));
    messages = messages.map((m: any) => m.id === id ? { ...m, read: true } : m);
    
    fs.writeFileSync(MESSAGES_PATH, JSON.stringify(messages, null, 2), "utf-8");
    res.json({ success: true });
  } catch (error) {
    console.error("POST /api/messages/:id/read xatolik:", error);
    res.status(500).json({ error: "Amalni bajarib bo'lmadi." });
  }
});

// 7. Delete Message (Admin only)
app.delete("/api/messages/:id", authenticateAdmin, (req, res) => {
  try {
    const { id } = req.params;
    if (!fs.existsSync(MESSAGES_PATH)) {
      res.status(404).json({ error: "Xabarlar topilmadi." });
      return;
    }

    let messages = JSON.parse(fs.readFileSync(MESSAGES_PATH, "utf-8"));
    messages = messages.filter((m: any) => m.id !== id);
    
    fs.writeFileSync(MESSAGES_PATH, JSON.stringify(messages, null, 2), "utf-8");
    res.json({ success: true, message: "Xabar muvaffaqiyatli o'chirildi." });
  } catch (error) {
    console.error("DELETE /api/messages/:id xatolik:", error);
    res.status(500).json({ error: "O'chirishda xatolik." });
  }
});

// 8. Base64 File Upload (Admin only)
app.post("/api/upload", authenticateAdmin, (req, res) => {
  try {
    const { fileName, fileType, base64Data } = req.body;
    if (!fileName || !base64Data) {
      res.status(400).json({ error: "Fayl nomi va tarkibi taqdim etilishi shart." });
      return;
    }

    // Clean base64 header (e.g. "data:image/png;base64,")
    const cleanBase64 = base64Data.replace(/^data:.*?;base64,/, "");
    const buffer = Buffer.from(cleanBase64, "base64");

    // Secure file name with timestamp
    const safeName = `${Date.now()}_${fileName.replace(/[^a-zA-Z0-9.-]/g, "_")}`;
    const filePath = path.join(UPLOADS_DIR, safeName);

    fs.writeFileSync(filePath, buffer);
    
    // Return relative URL that Express can serve statically
    res.json({ url: `/uploads/${safeName}` });
  } catch (error) {
    console.error("POST /api/upload xatolik:", error);
    res.status(500).json({ error: "Faylni yuklashda xatolik yuz berdi." });
  }
});

// --- VITE DEV OR PROD MIDDLWARE ---
async function startServer() {
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), "dist");
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on port ${PORT}`);
  });
}

startServer();
